MARKER = "# ---------------------------------------------------------------------------\n# Auth error-code translations."

# Build insertion
lines = []
lines.append("\n# Add missions to all 10 comprehensive languages")
lines.append("_MISSIONS_COMP = " + repr(MISSIONS_BY_LANG))
lines.append("\nfor _lang, _mdata in _MISSIONS_COMP.items():")
lines.append("    OVERRIDES[_lang]['missions'] = _mdata")
lines.append("\n# Add key missions strings to 14 partial languages")
lines.append("_MISSIONS_PARTIAL = " + repr(MISSIONS_PARTIAL))
lines.append("\nfor _lang, _mdata in _MISSIONS_PARTIAL.items():")
lines.append("    if _lang in OVERRIDES:")
lines.append("        OVERRIDES[_lang].setdefault('missions', {}).update(_mdata)")
lines.append("")

insertion = "\n".join(lines) + "\n"

assert MARKER in text
text = text.replace(MARKER, insertion + MARKER, 1)
SRC.write_text(text, encoding="utf-8")
print("Missions patch inserted")
